//  1. clear_merge_status=true → write NULL (state-changing actions invalidate
//     the prior verdict).
//  2. clear_merge_status=false, merge_status non-null → write the value.
//  3. clear_merge_status=false, merge_status null → preserve existing column.
func (q *Queries) UpsertGitLabMergeRequest(ctx context.Context, arg UpsertGitLabMergeRequestParams) (GitlabMergeRequest, error) {
	row := q.db.QueryRow(ctx, upsertGitLabMergeRequest,
		arg.WorkspaceID,
		arg.ConnectionID,
		arg.ProjectID,
		arg.NamespacePath,
		arg.ProjectPath,
		arg.MrIid,
		arg.Title,
		arg.State,
		arg.WebUrl,
		arg.MrCreatedAt,
		arg.MrUpdatedAt,
		arg.HeadSha,
		arg.Additions,
		arg.Deletions,
		arg.ChangedFiles,
		arg.SourceBranch,
		arg.AuthorUsername,
		arg.AuthorAvatarUrl,
		arg.MergedAt,
		arg.ClosedAt,
		arg.MergeStatus,
		arg.ClearMergeStatus,
	)
	var i GitlabMergeRequest
	err := row.Scan(
		&i.ID,
		&i.WorkspaceID,
		&i.ConnectionID,
		&i.ProjectID,
		&i.NamespacePath,
		&i.ProjectPath,
		&i.MrIid,
		&i.Title,
		&i.State,
		&i.WebUrl,
		&i.SourceBranch,
		&i.AuthorUsername,
		&i.AuthorAvatarUrl,
		&i.MergedAt,
		&i.ClosedAt,
		&i.MrCreatedAt,
		&i.MrUpdatedAt,
		&i.HeadSha,
		&i.MergeStatus,
		&i.Additions,
		&i.Deletions,
		&i.ChangedFiles,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

const upsertGitLabPipeline = `-- name: UpsertGitLabPipeline :exec

INSERT INTO gitlab_merge_request_pipeline (
    mr_id, pipeline_id, head_sha, status, updated_at
) VALUES (
    $1, $2, $3, $4, $5
)
ON CONFLICT (mr_id, pipeline_id) DO UPDATE SET
    head_sha   = EXCLUDED.head_sha,
    status     = EXCLUDED.status,
    updated_at = EXCLUDED.updated_at
WHERE EXCLUDED.updated_at >= gitlab_merge_request_pipeline.updated_at
`

type UpsertGitLabPipelineParams struct {
	MrID       pgtype.UUID        `json:"mr_id"`
	PipelineID int64              `json:"pipeline_id"`
	HeadSha    string             `json:"head_sha"`
	Status     string             `json:"status"`
	UpdatedAt  pgtype.Timestamptz `json:"updated_at"`
}

// =====================
// GitLab MR pipeline
// =====================
// Upserts a single pipeline row keyed by (mr_id, pipeline_id). The updated_at
// guard prevents a late-arriving older event from overwriting a newer one.
func (q *Queries) UpsertGitLabPipeline(ctx context.Context, arg UpsertGitLabPipelineParams) error {
	_, err := q.db.Exec(ctx, upsertGitLabPipeline,
		arg.MrID,
		arg.PipelineID,
		arg.HeadSha,
		arg.Status,
		arg.UpdatedAt,
	)
	return err
}

const upsertPendingPipeline = `-- name: UpsertPendingPipeline :exec

INSERT INTO gitlab_pending_pipeline (
    workspace_id, connection_id, project_id, mr_iid,
    pipeline_id, head_sha, status, pipeline_updated_at
) VALUES (
    $1, $2, $3, $4,
    $5, $6, $7, $8
)
ON CONFLICT (workspace_id, project_id, mr_iid, pipeline_id) DO UPDATE SET
    connection_id       = EXCLUDED.connection_id,
    head_sha            = EXCLUDED.head_sha,
    status              = EXCLUDED.status,
    pipeline_updated_at = EXCLUDED.pipeline_updated_at,
    received_at         = now()
WHERE EXCLUDED.pipeline_updated_at >= gitlab_pending_pipeline.pipeline_updated_at
`

type UpsertPendingPipelineParams struct {
	WorkspaceID       pgtype.UUID        `json:"workspace_id"`
	ConnectionID      pgtype.UUID        `json:"connection_id"`
	ProjectID         int64              `json:"project_id"`
	MrIid             int32              `json:"mr_iid"`
	PipelineID        int64              `json:"pipeline_id"`
	HeadSha           string             `json:"head_sha"`
	Status            string             `json:"status"`
	PipelineUpdatedAt pgtype.Timestamptz `json:"pipeline_updated_at"`
}

// =====================
// GitLab pending pipeline (out-of-order arrival stash)
// =====================
func (q *Queries) UpsertPendingPipeline(ctx context.Context, arg UpsertPendingPipelineParams) error {
	_, err := q.db.Exec(ctx, upsertPendingPipeline,
		arg.WorkspaceID,
		arg.ConnectionID,
		arg.ProjectID,
		arg.MrIid,
		arg.PipelineID,
		arg.HeadSha,
		arg.Status,
		arg.PipelineUpdatedAt,
	)
	return err
}
